import { getServerSession } from "next-auth"; import { NextResponse } from "next/server"; import { authOptions } from "../../../../lib/auth";
export async function GET(){ const session=await getServerSession(authOptions); if(!session?.user?.email) return NextResponse.json({error:"Unauthorized"},{status:401}); return NextResponse.json({ tab:"performance_cache", ttlDays:Number(process.env.CACHE_TTL_DAYS||7) }); }
